const { execSync } = require("child_process");
try {
  const result = execSync("npx tsc --noEmit --skipLibCheck src/app/projects/page.tsx", { encoding: "utf8", stdio: "pipe" });
  console.log("STDOUT:", result);
} catch (err) {
  console.log("EXIT CODE:", err.status);
  console.log("STDOUT:", err.stdout);
  console.log("STDERR:", err.stderr);
  if (err.stdout) console.log("FULL OUTPUT:", err.stdout.toString());
}

