  console.log("STDERR:", err.stderr?.toString() || "");
}

const { execSync } = require("child_process");
try {
  // Run tsc on the whole project to check for any type errors
  const result = execSync("npx tsc --noEmit --skipLibCheck", { encoding: "utf8", stdio: "pipe" });
  console.log("PASS: No TypeScript errors in the project");
} catch (err) {
  const stdout = err.stdout?.toString() || "";
  const stderr = err.stderr?.toString() || "";
  // Filter for only errors related to our files
  const lines = stdout.split("\n");
  const relevantErrors = lines.filter(line => 
    line.includes("page.tsx") || line.includes("create-project-modal.tsx")
  );
  if (relevantErrors.length > 0) {
    console.log("FAIL: Errors found:");
    relevantErrors.forEach(l => console.log(l));
  } else {
    console.log("PASS: No errors in projects page files");
    if (lines.some(l => l.includes("error TS"))) {
      console.log("(Note: Other files may have errors, but not in projects components)");
    }
  }
}

